.darma-loader-darma-custom-462 {color: var(--loader-color, #f97316);
   width: 60px;
   aspect-ratio: 1;
   display: grid;
   border-radius: 50%;
   background: radial-gradient(circle 15px, var(--loader-color, #f97316) 90%,#0000 );
   filter: drop-shadow(0px 0px 1px var(--loader-color, #f97316));
   animation: darma-loader-darma-custom-462-l2 1s infinite alternate linear;
}
.darma-loader-darma-custom-462::before, .darma-loader-darma-custom-462::after  {
  content: "";
   grid-area: 1/1;
   border-radius: 50%;
   --g:no-repeat linear-gradient(var(--loader-color, #f97316) 0 0) 50%;
   background: var(--g)/100% 5px, var(--g)/5px 100%;
   -webkit-mask: radial-gradient(farthest-side,#0000 60%,currentColor 61%);
}
.darma-loader-darma-custom-462::after  {
  transform: rotate(45deg);
}
@keyframes darma-loader-darma-custom-462-l2  {
  100% {filter:drop-shadow(0px 0px 20px var(--loader-color, #f97316))}
}

